import semantic_kernel as sk
from vex_sdk import VexFilter

kernel = sk.Kernel()

# Fintech compliance policy
fintech_policy = {
    'pci_dss': {'block_on': ['unencrypted_card_data', 'cvv_exposure']},
    'sox': {'require': ['calculation_validation', 'audit_trail']}
}

# Add Vex as kernel filter on ALL function results
@vex_filter(policy=fintech_policy)
def validate_financial_output(result: str) -> bool:
    return 'DISCLAIMER' in result and not any(pii in result for pii in ['card_number', 'ssn'])

kernel.add_function_filter(validate_financial_output)

# Now all plugin calls are automatically validated
result = await kernel.invoke('finance_plugin', 'calculate_risk_score', input={'amount': 100000})

import { Kernel } from '@semantic-kernel/core';
import { VexFilter } from 'vex-sdk';

const kernel = new Kernel();

// PCI DSS + BSA/AML compliance
const transactionPolicy = {
  pci_dss: { requireEncryption: true },
  bsa_aml: { sequenceValidation: ['kyc_check', 'aml_screen', 'transaction_execute'] }
};

kernel.addFunctionResultFilter(
  new VexFilter({
    policy: transactionPolicy,
    blockOn: ['unencrypted_amount', 'missing_aml_check'],
    require: ['transaction_id', 'audit_log']
  })
);

// Safe transaction execution
const result = await kernel.invoke('transaction_plugin', {
  function: 'execute_transfer',
  arguments: { toAccount: 'cust_123', amount: 50000 }
});

console.log('Compliant transaction:', result);
